#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding seasonal-affective-disorder-assessment (15 tables)..."

cargo loco generate scaffold patient \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    sex:string! \
    weight_kg:double \
    height_cm:double \
    bmi:double \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_demographics \
    assessment:references \
    preferred_name:string! \
    gender_identity:string! \
    ethnicity:string! \
    preferred_language:string! \
    interpreter_required:string! \
    gp_name:string! \
    gp_practice:string! \
    referrer_name:string! \
    referrer_role:string! \
    --htmx

cargo loco generate scaffold assessment_seasonal_pattern_history \
    assessment:references \
    worst_month:string! \
    best_month:string! \
    years_of_seasonal_symptoms:int \
    gss_sleep_length:int! \
    gss_social_activity:int! \
    gss_mood:int! \
    gss_weight:int! \
    gss_appetite:int! \
    gss_energy:int! \
    gss_total:int! \
    seasonal_pattern_is_problem:string! \
    seasonal_pattern_notes:text! \
    --htmx

cargo loco generate scaffold assessment_current_mood \
    assessment:references \
    phq9_interest:int! \
    phq9_feeling_down:int! \
    phq9_sleep:int! \
    phq9_tired:int! \
    phq9_appetite:int! \
    phq9_feeling_bad:int! \
    phq9_concentration:int! \
    phq9_moving_slowly:int! \
    phq9_self_harm:int! \
    phq9_total:int! \
    current_mood_notes:text! \
    --htmx

cargo loco generate scaffold assessment_sleep_energy \
    assessment:references \
    average_sleep_hours:double \
    sleep_quality:string! \
    difficulty_waking:string! \
    hypersomnia:string! \
    hypersomnia_hours:double \
    daytime_sleepiness:string! \
    energy_level:string! \
    energy_worst_time:string! \
    fatigue_impact:string! \
    sleep_energy_notes:text! \
    --htmx

cargo loco generate scaffold assessment_appetite_weight \
    assessment:references \
    appetite_change:string! \
    carbohydrate_craving:string! \
    carbohydrate_craving_severity:string! \
    chocolate_craving:string! \
    weight_change:string! \
    weight_change_kg:double \
    weight_change_period:string! \
    seasonal_weight_pattern:string! \
    appetite_weight_notes:text! \
    --htmx

cargo loco generate scaffold assessment_social_occupational \
    assessment:references \
    social_withdrawal:string! \
    relationship_impact:string! \
    work_performance:string! \
    days_missed_work:int \
    daily_activities_impact:string! \
    hobbies_interest:string! \
    employment_status:string! \
    occupation:string! \
    social_occupational_notes:text! \
    --htmx

cargo loco generate scaffold assessment_light_exposure \
    assessment:references \
    daily_outdoor_minutes:int \
    outdoor_time_of_day:string! \
    workplace_natural_light:string! \
    home_natural_light:string! \
    latitude_awareness:string! \
    uses_light_therapy:string! \
    light_therapy_details:text! \
    light_therapy_duration_minutes:int \
    light_therapy_lux:int \
    dawn_simulator:string! \
    light_exposure_notes:text! \
    --htmx

cargo loco generate scaffold assessment_previous_treatments \
    assessment:references \
    previous_sad_diagnosis:string! \
    previous_depression_diagnosis:string! \
    on_antidepressant:string! \
    antidepressant_details:text! \
    previous_antidepressant:string! \
    previous_antidepressant_details:text! \
    previous_light_therapy:string! \
    light_therapy_response:string! \
    previous_cbt:string! \
    cbt_response:string! \
    previous_other_therapy:string! \
    other_therapy_details:text! \
    vitamin_d_supplementation:string! \
    medication_adherence:string! \
    treatment_notes:text! \
    --htmx

cargo loco generate scaffold assessment_risk_assessment \
    assessment:references \
    suicidal_ideation:string! \
    suicidal_ideation_frequency:string! \
    suicidal_plan:string! \
    suicidal_intent:string! \
    previous_self_harm:string! \
    previous_self_harm_details:text! \
    previous_suicide_attempt:string! \
    previous_attempt_details:text! \
    hopelessness:string! \
    protective_factors:text! \
    risk_level:string! \
    safety_plan_in_place:string! \
    risk_assessment_notes:text! \
    --htmx

cargo loco generate scaffold assessment_treatment_plan \
    assessment:references \
    light_therapy_recommended:string! \
    light_therapy_prescription:text! \
    antidepressant_recommended:string! \
    antidepressant_prescription:text! \
    cbt_recommended:string! \
    exercise_recommended:string! \
    exercise_details:text! \
    lifestyle_advice:text! \
    vitamin_d_recommended:string! \
    follow_up_interval:string! \
    follow_up_date:date \
    referral_required:string! \
    referral_to:string! \
    crisis_plan:text! \
    treatment_plan_notes:text! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    gss_total:int! \
    gss_category:string! \
    phq9_total:int! \
    phq9_severity:string! \
    combined_severity:string! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    severity_level:string! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
